import requests

BASE_URL = "http://localhost:3001"
LOGIN_ENDPOINT = "/api/auth/login"
TIMEOUT = 30

def test_post_apiauthlogin_valid_and_invalid_credentials():
    url = BASE_URL + LOGIN_ENDPOINT

    # Valid credentials (use correct admin credentials as per instructions)
    valid_payload = {
        "email": "admin@example.com",
        "password": "AdminPassword123!"
    }

    try:
        valid_response = requests.post(url, json=valid_payload, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Valid credentials request failed: {e}"

    assert valid_response.status_code == 200, f"Expected 200 OK for valid credentials, got {valid_response.status_code}"
    try:
        valid_json = valid_response.json()
    except ValueError:
        assert False, "Valid credentials response is not valid JSON"

    # Assert JWT token presence in response (could be in a field like 'token')
    assert "token" in valid_json or "accessToken" in valid_json, "JWT token not found in valid login response"

    # Invalid credentials (wrong password)
    invalid_payload = {
        "email": "admin@example.com",
        "password": "WrongPassword!"
    }

    try:
        invalid_response = requests.post(url, json=invalid_payload, timeout=TIMEOUT)
    except requests.RequestException as e:
        assert False, f"Invalid credentials request failed: {e}"

    assert invalid_response.status_code == 401, f"Expected 401 Unauthorized for invalid credentials, got {invalid_response.status_code}"
    try:
        invalid_json = invalid_response.json()
    except ValueError:
        assert False, "Invalid credentials response is not valid JSON"

    # Assert error message
    error_message = invalid_json.get("error") or invalid_json.get("message") or ""
    assert "Invalid credentials" in error_message, f"Expected 'Invalid credentials' message, got: {error_message}"

test_post_apiauthlogin_valid_and_invalid_credentials()

import requests

BASE_URL = "http://localhost:3001"
TIMEOUT = 30

def test_post_apihotspotpurchase_with_valid_and_invalid_payment_details():
    url = f"{BASE_URL}/api/hotspot/purchase"

    # Valid purchase payload simplified to required fields
    valid_payload = {
        "username": "testuser1",
        "routerId": 1,
        "packageId": 1,
        "paymentInfo": {
            "method": "mpesa",
            "amount": 100.0
        }
    }

    # Invalid payment payloads examples
    invalid_payloads = [
        # Insufficient funds / payment required scenario
        {
            "username": "testuser1",
            "routerId": 1,
            "packageId": 1,
            "paymentInfo": {
                "method": "mpesa",
                "amount": 0.0  # zero or insufficient amount
            }
        },
        # Invalid payment method scenario
        {
            "username": "testuser1",
            "routerId": 1,
            "packageId": 1,
            "paymentInfo": {
                "method": "invalid_method",
                "amount": 100.0
            }
        }
    ]

    headers = {
        "Content-Type": "application/json"
    }

    # Test valid purchase
    try:
        resp = requests.post(url, json=valid_payload, headers=headers, timeout=TIMEOUT)
        assert resp.status_code == 200, f"Expected 200 OK for valid purchase, got {resp.status_code}"
        json_resp = resp.json()
        assert ("voucher" in json_resp or "activation" in json_resp), "Response must include voucher or activation details"
    except requests.RequestException as e:
        assert False, f"Valid purchase request failed: {e}"

    # Test invalid payment scenarios
    for idx, payload in enumerate(invalid_payloads):
        try:
            resp = requests.post(url, json=payload, headers=headers, timeout=TIMEOUT)
            assert resp.status_code in (400, 402), \
                f"Expected 400 or 402 for invalid payment in test case {idx}, got {resp.status_code}"
            json_resp = resp.json()
            error_message = json_resp.get("error") or json_resp.get("message") or ""
            assert error_message != "", \
                f"Expected error message in test case {idx}, got: {json_resp}"
        except requests.RequestException as e:
            assert False, f"Invalid payment request {idx} failed: {e}"


test_post_apihotspotpurchase_with_valid_and_invalid_payment_details()
